sdf__v3.code:
float sdSegment(vec2 p, vec2 a, vec2 b) {
    vec2 pa = p - a, ba = b - a;
    float h = clamp(dot(pa,ba)/dot(ba,ba), 0.0, 1.0);
    return length(pa - ba*h);
}
void main() {
    vec2 p = v_uv * 2.0 - 1.0;
    float d = sdSegment(p, vec2(-0.6, 0.0), vec2(0.6, 0.0));
    float line = smoothstep(0.06, 0.0, d);
