raymarch.code:
float sdSphere(vec3 p, float r){ return length(p) - r; }
vec3 calcNormal(vec3 p){
    float e = 0.001;
    vec2 h = vec2(e, 0.0);
    float dx = sdSphere(p + vec3(h.x, h.y, h.y), 0.6) - sdSphere(p - vec3(h.x, h.y, h.y), 0.6);
    float dy = sdSphere(p + vec3(h.y, h.x, h.y), 0.6) - sdSphere(p - vec3(h.y, h.x, h.y), 0.6);
    float dz = sdSphere(p + vec3(h.y, h.y, h.x), 0.6) - sdSphere(p - vec3(h.y, h.y, h.x), 0.6);
    return normalize(vec3(dx,dy,dz));
}
void main() {
    vec2 uv = v_uv * 2.0 - 1.0;
    uv.x *= u_resolution.x / u_resolution.y;
    vec3 ro = vec3(0.0, 0.0, 2.5);
    vec3 rd = normalize(vec3(uv, -1.5));
    float t = 0.0;
    float hit = 0.0;
    for(int i=0;i<64;i++){
        vec3 p = ro + rd * t;
        float d = sdSphere(p, 0.6);
        if(d < 0.001){ hit = 1.0; break; }
        t += d;
        if(t > 6.0) break;
    }
    vec3 col = vec3(0.0);
    if(hit > 0.5){
        vec3 p = ro + rd * t;
        vec3 n = calcNormal(p);
        vec3 l = normalize(vec3(0.6, 0.7, 0.2));
        float diff = max(dot(n,l), 0.0);
        col = vec3(diff);
    }
    fragColor = vec4(col, 1.0);
}

raymarch__v2.code:
