    vec3 q = abs(p) - b;
    return length(max(q,0.0)) + min(max(q.x,max(q.y,q.z)),0.0);
}
void main() {
    vec2 uv = v_uv * 2.0 - 1.0;
    uv.x *= u_resolution.x / u_resolution.y;
    vec3 ro = vec3(0.0, 0.0, 2.2);
    vec3 rd = normalize(vec3(uv, -1.2));
    float t = 0.0;
    float hit = 0.0;
    for(int i=0;i<72;i++){
        vec3 p = ro + rd * t;
        float d = sdBox(p, vec3(0.5));
        if(d < 0.001){ hit = 1.0; break; }
        t += d;
        if(t > 6.0) break;
    }
    float shade = hit * (1.0 - t / 6.0);
    fragColor = vec4(vec3(shade), 1.0);
}

raymarch__v3.code:
float sdTorus(vec3 p, vec2 t){
    vec2 q = vec2(length(p.xz) - t.x, p.y);
    return length(q) - t.y;
}
void main() {
    vec2 uv = v_uv * 2.0 - 1.0;
    uv.x *= u_resolution.x / u_resolution.y;
    vec3 ro = vec3(0.0, 0.0, 2.6);
    vec3 rd = normalize(vec3(uv, -1.6));
    float t = 0.0;
    float hit = 0.0;
    for(int i=0;i<80;i++){
        vec3 p = ro + rd * t;
        p.xy *= mat2(cos(u_time*0.4), -sin(u_time*0.4), sin(u_time*0.4), cos(u_time*0.4));
        float d = sdTorus(p, vec2(0.55, 0.18));
        if(d < 0.001){ hit = 1.0; break; }
        t += d;
        if(t > 7.0) break;
    }
    fragColor = vec4(vec3(hit), 1.0);
}

