prim_noise_worley.code:
float worley(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float md = 10.0;
    for (int y = -1; y <= 1; y++) {
        for (int x = -1; x <= 1; x++) {
            vec2 g = vec2(float(x), float(y));
            vec3 h = hash3(i + g);
            vec2 o = g + h.xy * 0.80;
            float d = length(f - o);
            md = min(md, d);
        }
    }
    return md;
}
