prim_blur_box.code:
void main() {
    vec2 uv = v_uv;
    vec2 px = 1.0 / u_resolution;
    vec4 sum = vec4(0.0);
    int R = 1;
    float cnt = 0.0;
    for (int y = -1; y <= 1; y++) {
        for (int x = -1; x <= 1; x++) {
            vec2 o = vec2(float(x), float(y)) * px;
            sum += texture(u_input0, uv + o);
            cnt += 1.0;
        }
    }
    fragColor = sum / cnt;
}

