prim_edge_sobel.code:
void main() {
    vec2 uv = v_uv;
    vec2 px = 1.0 / u_resolution;

    float tl = dot(texture(u_input0, uv + px*vec2(-1.0,  1.0)).rgb, vec3(0.299,0.587,0.114));
    float  l = dot(texture(u_input0, uv + px*vec2(-1.0,  0.0)).rgb, vec3(0.299,0.587,0.114));
    float bl = dot(texture(u_input0, uv + px*vec2(-1.0, -1.0)).rgb, vec3(0.299,0.587,0.114));

    float  t = dot(texture(u_input0, uv + px*vec2( 0.0,  1.0)).rgb, vec3(0.299,0.587,0.114));
    float  c = dot(texture(u_input0, uv).rgb, vec3(0.299,0.587,0.114));
    float  b = dot(texture(u_input0, uv + px*vec2( 0.0, -1.0)).rgb, vec3(0.299,0.587,0.114));

    float tr = dot(texture(u_input0, uv + px*vec2( 1.0,  1.0)).rgb, vec3(0.299,0.587,0.114));
    float  r = dot(texture(u_input0, uv + px*vec2( 1.0,  0.0)).rgb, vec3(0.299,0.587,0.114));
    float br = dot(texture(u_input0, uv + px*vec2( 1.0, -1.0)).rgb, vec3(0.299,0.587,0.114));

    float gx = -tl - 2.0*l - bl + tr + 2.0*r + br;
    float gy = -bl - 2.0*b - br + tl + 2.0*t + tr;

    float e = clamp(length(vec2(gx, gy))*1.00, 0.0, 1.0);
    fragColor = vec4(vec3(e), 1.0);
}

