    vec2 uv = v_uv*2.0 - 1.0;
    float a = atan(uv.y, uv.x);
    float r = length(uv);
    float n = 4.0;
    float seg = 6.28318 / n;
    a = mod(a, seg);
    a = abs(a - seg*0.5);
    vec2 p = vec2(cos(a), sin(a)) * r;
