void main() {
    vec2 uv = v_uv;
    vec2 px = 1.0 / max(u_resolution, vec2(1.0));
    float gx[9];
    float gy[9];
    gx[0] = -1.0; gx[1] = 0.0; gx[2] = 1.0;
    gx[3] = -2.0; gx[4] = 0.0; gx[5] = 2.0;
    gx[6] = -1.0; gx[7] = 0.0; gx[8] = 1.0;

    gy[0] = -1.0; gy[1] = -2.0; gy[2] = -1.0;
    gy[3] =  0.0; gy[4] =  0.0; gy[5] =  0.0;
    gy[6] =  1.0; gy[7] =  2.0; gy[8] =  1.0;

    float sx = 0.0;
    float sy = 0.0;
    int k = 0;
    for (int j = -1; j <= 1; j++) {
        for (int i = -1; i <= 1; i++) {
            vec3 c = texture(u_input0, uv + px * vec2(float(i), float(j))).rgb;
            float l = dot(c, vec3(0.299, 0.587, 0.114));
            sx += l * gx[k];
            sy += l * gy[k];
            k++;
        }
    }
    float e = clamp(sqrt(sx*sx + sy*sy), 0.0, 1.0);
    fragColor = vec4(vec3(e), 1.0);
}

