const count = Math.floor(params.count || 256);
const positions = new Float32Array(count * 3);
const velocities = new Float32Array(count * 3);
for (let i = 0; i < count; i++) {
  positions[i*3+0] = (Math.random() - 0.5) * 2.0;
  positions[i*3+1] = (Math.random() - 0.5) * 2.0;
  positions[i*3+2] = (Math.random() - 0.5) * 0.5;
  velocities[i*3+0] = (Math.random() - 0.5) * 0.01;
  velocities[i*3+1] = (Math.random() - 0.5) * 0.01;
  velocities[i*3+2] = 0.0;
}

const geo = new THREE.BufferGeometry();
const attr = new THREE.Float32BufferAttribute(positions, 3);
geo.setAttribute('position', attr);

const mat = new THREE.PointsMaterial({ size: params.size || 0.03, color: params.color || 0xffffff });
const points = new THREE.Points(geo, mat);
scene.add(points);

camera.position.z = 3;

return {
  points,
  update: (t) => {
    for (let i = 0; i < count; i++) {
      positions[i*3+0] += velocities[i*3+0];
      positions[i*3+1] += velocities[i*3+1];
      if (positions[i*3+0] > 1.0) positions[i*3+0] = -1.0;
      if (positions[i*3+0] < -1.0) positions[i*3+0] = 1.0;
      if (positions[i*3+1] > 1.0) positions[i*3+1] = -1.0;
      if (positions[i*3+1] < -1.0) positions[i*3+1] = 1.0;
    }
    attr.needsUpdate = true;
    points.rotation.z = t * 0.1;
  }
};

