camera.position.z = 3;
const state = { radius: 3.0 };

return {
  state,
  update: (t) => {
    const r = state.radius;
    camera.position.x = Math.cos(t * 0.2) * r;
    camera.position.z = Math.sin(t * 0.2) * r;
    camera.position.y = Math.sin(t * 0.15) * 0.5;
    camera.lookAt(0, 0, 0);
  }
};

