prim_plane_grid.code:
// primitive wire grid plane
const geo = new THREE.PlaneGeometry(6, 6, 32, 32);
const mat = new THREE.MeshBasicMaterial({ color: params.color || 0xffffff, wireframe: true, transparent: true, opacity: 0.85 });
const mesh = new THREE.Mesh(geo, mat);
scene.add(mesh);

camera.position.z = params.camZ || 5;
mesh.rotation.x = -0.9;

const pos = geo.attributes.position;
const base = new Float32Array(pos.array.length);
base.set(pos.array);

return {
  update: (t) => {
    for (let i = 0; i < pos.count; i++) {
      const ix = i * 3;
      const x = base[ix+0];
      const y = base[ix+1];
      pos.array[ix+2] = Math.sin(x*1.2 + t) * Math.cos(y*1.2 + t*0.7) * 0.20;
    }
    pos.needsUpdate = true;
  }
};

