prim_line_spiral.code:
// primitive line spiral
const points = [];
const total = 300;
for (let i = 0; i < total; i++) {
  const t = i / (total-1);
  const a = t * Math.PI * 2 * 3;
  const r = 0.2 + t * 2.0;
  points.push(new THREE.Vector3(Math.cos(a)*r, Math.sin(a)*r, (t-0.5)*2.0));
}
const geo = new THREE.BufferGeometry().setFromPoints(points);
const mat = new THREE.LineBasicMaterial({ color: params.color || 0xffffff, transparent: true, opacity: 0.9 });
const line = new THREE.Line(geo, mat);
scene.add(line);

camera.position.z = params.camZ || 6;

return {
  update: (t) => {
    line.rotation.z = t * 0.2;
    line.rotation.y = t * 0.15;
  }
};

