// Instanced grid of boxes (SOP instancing)
const nx = Math.max(1, Math.floor(params.nx || 20));
const ny = Math.max(1, Math.floor(params.ny || 20));
const spacing = params.spacing || 0.12;

const geo = new THREE.BoxGeometry(0.05, 0.05, 0.05);
const mat = new THREE.MeshNormalMaterial();
const inst = new THREE.InstancedMesh(geo, mat, nx * ny);

let idx = 0;
const m = new THREE.Matrix4();
for (let y = 0; y < ny; y++) {
  for (let x = 0; x < nx; x++) {
    const px = (x - nx * 0.5) * spacing;
    const py = (y - ny * 0.5) * spacing;
    m.makeTranslation(px, py, 0);
    inst.setMatrixAt(idx++, m);
  }
}
scene.add(inst);

camera.position.z = params.cameraZ || 3.0;

return {
  inst,
  update: (t) => {
    inst.rotation.z = t * 0.15;
  }
};

