// Points cloud (particle renderer SOP)
const count = Math.max(256, Math.floor(params.count || 5000));
const radius = params.radius || 1.0;

const geo = new THREE.BufferGeometry();
const pos = new Float32Array(count * 3);
for (let i = 0; i < count; i++) {
  const a = Math.random() * 6.28318;
  const r = Math.sqrt(Math.random()) * radius;
  pos[i * 3 + 0] = Math.cos(a) * r;
  pos[i * 3 + 1] = (Math.random() - 0.5) * 0.2;
  pos[i * 3 + 2] = Math.sin(a) * r;
}
geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));

const mat = new THREE.PointsMaterial({
  size: params.size || 0.01,
  transparent: true,
  opacity: params.opacity || 0.9,
  depthWrite: false,
  color: new THREE.Color(params.color || 0xffffff)
});

const points = new THREE.Points(geo, mat);
scene.add(points);

camera.position.z = params.cameraZ || 2.5;

return {
  points,
  update: (t) => {
    points.rotation.y = t * 0.2;
    points.rotation.x = t * 0.12;
  }
};

