// Polyline waveform (curve SOP)
const segments = Math.max(32, Math.floor(params.segments || 256));
const geo = new THREE.BufferGeometry();
const pos = new Float32Array(segments * 3);
geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));

const mat = new THREE.LineBasicMaterial({ color: new THREE.Color(params.color || 0xffffff) });
const line = new THREE.Line(geo, mat);
scene.add(line);

camera.position.z = params.cameraZ || 2.0;

return {
  line,
  update: (t) => {
    for (let i = 0; i < segments; i++) {
      const x = (i / (segments - 1)) * 2.0 - 1.0;
      const y = Math.sin(x * (params.freq || 8.0) + t * (params.speed || 1.0)) * (params.amp || 0.2);
      pos[i * 3 + 0] = x;
      pos[i * 3 + 1] = y;
      pos[i * 3 + 2] = 0.0;
    }
    geo.attributes.position.needsUpdate = true;
  }
};

