    const amp = params.amp || 0.15;
    const freq = params.freq || 2.0;
    for (let i = 0; i < pos.count; i++) {
      const x = pos.getX(i);
      const z = pos.getZ(i);
      const y = Math.sin((x + z) * freq + t) * amp;
      pos.setY(i, y);
    }
    pos.needsUpdate = true;
    geo.computeVertexNormals();
  }
};

