fft_analyzer__v4.code:
const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 1024;
const dataArray = new Uint8Array(analyser.frequencyBinCount);
const state = { low: 0, mid: 0, high: 0 };

return {
  analyser,
  dataArray,
  state,
  update: () => {
    analyser.getByteFrequencyData(dataArray);
    const n = dataArray.length;
    let low=0, mid=0, high=0;
    for (let i=0;i<n;i++){
      const v = dataArray[i];
      if (i < n*0.2) low += v;
      else if (i < n*0.6) mid += v;
      else high += v;
    }
    state.low = low / Math.max(1, n*0.2);
    state.mid = mid / Math.max(1, n*0.4);
    state.high = high / Math.max(1, n*0.4);
    return dataArray;
  }
};

