prim_beat_detector.code:
// primitive beat detector (energy + adaptive threshold)
const osc = audioCtx.createOscillator();
osc.type = params.type || 'sawtooth';
osc.frequency.value = params.frequency || 110;

const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 256;

osc.connect(analyser);
analyser.connect(audioCtx.destination);
osc.start();

const dataArray = new Uint8Array(analyser.frequencyBinCount);

const state = {
  energy: 0,
  threshold: params.threshold || 0.25,
  beat: 0
};

return {
  analyser,
  dataArray,
  state,
  update: () => {
    analyser.getByteFrequencyData(dataArray);
    let sum = 0;
    for (let i = 0; i < dataArray.length; i++) sum += dataArray[i];
    const e = sum / (dataArray.length * 255);
    state.energy = e;
    state.threshold = Math.max(state.threshold*0.900, params.minThreshold || 0.05);
    const beat = e > state.threshold ? 1 : 0;
    if (beat) state.threshold = e + 0.05;
    state.beat = beat;
    return beat;
  }
};

