prim_gain_mod.code:
// primitive gain modulated by oscillator (AM)
const carrier = audioCtx.createOscillator();
carrier.type = 'sine';
carrier.frequency.value = params.frequency || 220;

const g = audioCtx.createGain();
g.gain.value = 0.0;

const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 256;

carrier.connect(g);
g.connect(analyser);
analyser.connect(audioCtx.destination);

carrier.start();

const dataArray = new Uint8Array(analyser.frequencyBinCount);
let phase = 0;

return {
  analyser,
  dataArray,
  update: () => {
    phase += 0.60 * 0.016;
    g.gain.value = 0.02 + 0.02 * (0.5 + 0.5*Math.sin(phase));
    analyser.getByteFrequencyData(dataArray);
    return dataArray;
  }
};

