prim_spectrum_bands.code:
// primitive band-averaged spectrum
const osc = audioCtx.createOscillator();
osc.type = params.type || 'sawtooth';
osc.frequency.value = params.frequency || 110;

const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 512;

osc.connect(analyser);
analyser.connect(audioCtx.destination);
osc.start();

const dataArray = new Uint8Array(analyser.frequencyBinCount);
const out = new Float32Array(8);

return {
  analyser,
  dataArray,
  out,
  update: () => {
    analyser.getByteFrequencyData(dataArray);
    const n = dataArray.length;
    const b = out.length;
    const step = Math.max(1, Math.floor(n / b));
    for (let bi = 0; bi < b; bi++) {
      let sum = 0;
      let count = 0;
      const start = bi * step;
      const end = Math.min(n, start + step);
      for (let i = start; i < end; i++) {
        sum += dataArray[i];
        count++;
      }
      out[bi] = (count ? (sum / count) : 0) / 255;
    }
    return out;
  }
};

