prim_envelope.code:
// primitive envelope follower (attack/release)
const osc = audioCtx.createOscillator();
osc.type = params.type || 'sawtooth';
osc.frequency.value = params.frequency || 220;

const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 256;

osc.connect(analyser);
analyser.connect(audioCtx.destination);
osc.start();

const dataArray = new Uint8Array(analyser.frequencyBinCount);

const state = {
  env: 0,
  attack: params.attack || 0.05,
  release: params.release || 0.20
};

return {
  analyser,
  dataArray,
  state,
  update: () => {
    analyser.getByteFrequencyData(dataArray);
    let sum = 0;
    for (let i = 0; i < dataArray.length; i++) sum += dataArray[i];
    const e = sum / (dataArray.length * 255);
    const a = state.attack;
    const r = state.release;
    state.env = e > state.env ? (state.env + (e - state.env) * a) : (state.env + (e - state.env) * r);
    return state.env;
  }
};

