// Amplitude follower (Max average~ / snapshot~)
const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 512;
analyser.smoothingTimeConstant = params.smoothing || 0.9;

const buf = new Uint8Array(analyser.fftSize);

let state = { amp: 0.0 };

return {
  analyser,
  state,
  update: () => {
    analyser.getByteTimeDomainData(buf);
    let sum = 0.0;
    for (let i = 0; i < buf.length; i++) {
      const v = (buf[i] - 128) / 128;
      sum += v * v;
    }
    const rms = Math.sqrt(sum / buf.length);
    const smooth = params.smooth || 0.2;
    state.amp = state.amp + (rms - state.amp) * smooth;
    return state.amp;
  }
};

