// Beat detector (peak follower)
const analyser = audioCtx.createAnalyser();
analyser.fftSize = params.fftSize || 512;
analyser.smoothingTimeConstant = params.smoothing || 0.8;

const buf = new Uint8Array(analyser.frequencyBinCount);

let state = { beat: 0.0, level: 0.0, threshold: params.threshold || 0.25 };

return {
  analyser,
  state,
  update: () => {
    analyser.getByteFrequencyData(buf);
    // crude energy in low band
    let sum = 0.0;
    const bins = Math.min(32, buf.length);
    for (let i = 0; i < bins; i++) sum += buf[i] / 255.0;
    const level = sum / bins;
    state.level = state.level + (level - state.level) * (params.smooth || 0.2);

    const hit = state.level > state.threshold ? 1.0 : 0.0;
    state.beat = Math.max(hit, state.beat * (params.decay || 0.9));
    state.threshold = params.threshold || state.threshold;
    return state.beat;
  }
};

