// primitive step sequencer (0..1)
const state = {
  value: 0,
  steps: params.steps ?? 4,
  rate: params.rate ?? 2.0
};
return {
  state,
  get: () => state.value,
  set: (v) => { /* optional external override */ state.value = v; },
  update: (t) => {
    const idx = Math.floor(t * state.rate) % state.steps;
    state.value = idx / Math.max(1, state.steps - 1);
    return state.value;
  }
};

