// Moving circle (2D vector TOP)
const w = canvas.width, h = canvas.height;
return {
  update: (t) => {
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = params.color || '#ffffff';
    const r = params.radius || Math.min(w, h) * 0.08;
    const x = w * (0.5 + 0.3 * Math.sin(t * (params.speed || 1.0)));
    const y = h * (0.5 + 0.3 * Math.cos(t * (params.speed || 1.0)));
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
  }
};

