// Waveform polyline (2D CHOP->TOP style)
const w = canvas.width, h = canvas.height;
return {
  update: (t, inputs) => {
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = params.color || '#ffffff';
    ctx.lineWidth = params.lineWidth || 2;

    ctx.beginPath();
    const n = Math.max(64, Math.floor(params.samples || 256));
    for (let i = 0; i < n; i++) {
      const x = (i / (n - 1)) * w;
      const y = h * 0.5 + Math.sin((i / n) * (params.freq || 10) * Math.PI * 2 + t * (params.speed || 1)) * (params.amp || 0.25) * h;
      if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }
};

