// Particle scribble (2D particle)
const w = canvas.width, h = canvas.height;
const count = Math.max(128, Math.floor(params.count || 500));
const p = Array.from({length: count}, () => ({
  x: Math.random() * w,
  y: Math.random() * h,
  vx: (Math.random() - 0.5) * 40,
  vy: (Math.random() - 0.5) * 40
}));
return {
  update: (t) => {
    const dt = 1/60;
    ctx.fillStyle = params.fade || 'rgba(0,0,0,0.08)';
    ctx.fillRect(0, 0, w, h);

    ctx.fillStyle = params.color || '#ffffff';
    for (const a of p) {
      a.x += a.vx * dt; a.y += a.vy * dt;
      a.vx += Math.sin(t + a.y * 0.01) * 2.0;
      a.vy += Math.cos(t + a.x * 0.01) * 2.0;

      if (a.x < 0) a.x += w; if (a.x >= w) a.x -= w;
      if (a.y < 0) a.y += h; if (a.y >= h) a.y -= h;

      ctx.fillRect(a.x, a.y, 2, 2);
    }
  }
};

