// Lissajous curve
const w = canvas.width, h = canvas.height;
return {
  update: (t) => {
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = params.color || '#ffffff';
    ctx.lineWidth = params.lineWidth || 2;
    const A = params.A || 3, B = params.B || 2;
    const a = params.a || 0.8, b = params.b || 0.8;

    ctx.beginPath();
    const n = 800;
    for (let i = 0; i <= n; i++) {
      const u = (i / n) * Math.PI * 2;
      const x = w * 0.5 + Math.sin(u * A + t * a) * w * 0.35;
      const y = h * 0.5 + Math.sin(u * B + t * b) * h * 0.35;
      if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }
};

