// Vector field arrows
const w = canvas.width, h = canvas.height;
return {
  update: (t) => {
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = params.color || '#ffffff';
    ctx.lineWidth = 1;

    const step = Math.max(16, Math.floor(params.step || 32));
    for (let y = step; y < h; y += step) {
      for (let x = step; x < w; x += step) {
        const nx = x / w, ny = y / h;
        const a = Math.sin((nx * 6 + t) * 1.5) + Math.cos((ny * 6 - t) * 1.2);
        const vx = Math.cos(a) * step * 0.25;
        const vy = Math.sin(a) * step * 0.25;

        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + vx, y + vy);
        ctx.stroke();
      }
    }
  }
};

