struct Uniforms {
  time: f32,
  width: f32,
  height: f32,
  p0: f32,
  p1: f32,
  p2: f32,
  p3: f32,
  _pad: f32,
};

@group(0) @binding(0) var u_input : texture_2d<f32>;
@group(0) @binding(1) var u_samp : sampler;
@group(0) @binding(2) var u_output : texture_storage_2d<rgba8unorm, write>;
@group(0) @binding(3) var<uniform> U : Uniforms;

fn hash(p: vec2<f32>) -> f32 {
  let h = sin(dot(p, vec2<f32>(127.1, 311.7))) * 43758.5453;
  return fract(h);
}

fn clamp01(x: f32) -> f32 { return clamp(x, 0.0, 1.0); }


@compute @workgroup_size(8, 8)
fn main(@builtin(global_invocation_id) gid : vec3<u32>) {
  let x = gid.x;
  let y = gid.y;
  if (x >= u32(U.width) || y >= u32(U.height)) { return; }
  let uv = vec2<f32>(f32(x) / max(U.width - 1.0, 1.0), f32(y) / max(U.height - 1.0, 1.0));
  let c = vec4<f32>(uv.x, uv.y, 0.5 + 0.5 * sin(U.time), 1.0);
  textureStore(u_output, vec2<i32>(i32(x), i32(y)), c);
}

