// Particle gravity field (CPU physics)
const n = Math.max(64, Math.floor(params.count || 512));
const state = {
  x: new Float32Array(n),
  y: new Float32Array(n),
  vx: new Float32Array(n),
  vy: new Float32Array(n)
};
for (let i = 0; i < n; i++) {
  state.x[i] = Math.random();
  state.y[i] = Math.random();
  state.vx[i] = (Math.random() - 0.5) * 0.1;
  state.vy[i] = (Math.random() - 0.5) * 0.1;
}
return {
  state,
  update: (t, dt) => {
    const g = params.g || 0.8;
    for (let i = 0; i < n; i++) {
      state.vy[i] -= g * dt;
      state.x[i] += state.vx[i] * dt;
      state.y[i] += state.vy[i] * dt;
      // bounds
      if (state.x[i] < 0) { state.x[i] = 0; state.vx[i] *= -0.8; }
      if (state.x[i] > 1) { state.x[i] = 1; state.vx[i] *= -0.8; }
      if (state.y[i] < 0) { state.y[i] = 0; state.vy[i] *= -0.6; }
      if (state.y[i] > 1) { state.y[i] = 1; state.vy[i] *= -0.6; }
    }
    return state;
  }
};

