// Verlet cloth-lite (grid points with constraints)
const nx = Math.max(4, Math.floor(params.nx || 16));
const ny = Math.max(4, Math.floor(params.ny || 10));
const n = nx * ny;
const p = new Float32Array(n * 2);
const p0 = new Float32Array(n * 2);

for (let j = 0; j < ny; j++) {
  for (let i = 0; i < nx; i++) {
    const id = (j * nx + i) * 2;
    p[id+0] = i / (nx - 1);
    p[id+1] = 0.2 + j / (ny - 1) * 0.5;
    p0[id+0] = p[id+0];
    p0[id+1] = p[id+1];
  }
}

function satisfy(a, b, rest, stiff) {
  const ax = p[a], ay = p[a+1];
  const bx = p[b], by = p[b+1];
  const dx = bx - ax, dy = by - ay;
  const d = Math.sqrt(dx*dx + dy*dy) + 1e-6;
  const diff = (d - rest) / d;
  const ox = dx * 0.5 * diff * stiff;
  const oy = dy * 0.5 * diff * stiff;
  p[a] += ox; p[a+1] += oy;
  p[b] -= ox; p[b+1] -= oy;
}

return {
  state: { nx, ny, p },
  update: (t, dt) => {
    const g = params.g || 0.6;
    const damp = params.damp || 0.99;
    // verlet integrate
    for (let i = 0; i < n; i++) {
      const id = i*2;
      const x = p[id], y = p[id+1];
      const vx = (x - p0[id]) * damp;
      const vy = (y - p0[id+1]) * damp - g * dt * dt;
      p0[id] = x; p0[id+1] = y;
      p[id] = x + vx;
      p[id+1] = y + vy;
    }
    // constraints
    const restX = 1.0 / (nx - 1);
    const restY = 0.5 / (ny - 1);
    const stiff = params.stiff || 0.7;
    for (let it = 0; it < 4; it++) {
      for (let j = 0; j < ny; j++) {
        for (let i = 0; i < nx; i++) {
          const id = (j*nx+i)*2;
          if (i+1 < nx) satisfy(id, id+2, restX, stiff);
          if (j+1 < ny) satisfy(id, id+nx*2, restY, stiff);
        }
      }
      // pin top row
      for (let i = 0; i < nx; i++) {
        const id = i*2;
        p[id] = i/(nx-1);
        p[id+1] = 0.2;
      }
    }
    return { nx, ny, p };
  }
};

