// Simple boids steering (flocking)
const n = Math.max(32, Math.floor(params.count || 200));
const boids = Array.from({length:n}, () => ({
  x: Math.random(), y: Math.random(),
  vx: (Math.random()-0.5)*0.2, vy: (Math.random()-0.5)*0.2
}));

return {
  state: { boids },
  update: (t, dt) => {
    const sepD = params.sepDist || 0.03;
    const aliD = params.aliDist || 0.08;
    const cohD = params.cohDist || 0.10;

    const sepK = params.sepK || 1.2;
    const aliK = params.aliK || 0.6;
    const cohK = params.cohK || 0.4;

    for (let i = 0; i < n; i++) {
      const a = boids[i];
      let sx=0, sy=0, ax=0, ay=0, cx=0, cy=0;
      let sc=0, ac=0, cc=0;

      for (let j = 0; j < n; j++) {
        if (i === j) continue;
        const b = boids[j];
        let dx = b.x - a.x; let dy = b.y - a.y;
        // wrap distances
        if (dx > 0.5) dx -= 1; if (dx < -0.5) dx += 1;
        if (dy > 0.5) dy -= 1; if (dy < -0.5) dy += 1;

        const d2 = dx*dx + dy*dy;
        if (d2 < sepD*sepD) { sx -= dx; sy -= dy; sc++; }
        if (d2 < aliD*aliD) { ax += b.vx; ay += b.vy; ac++; }
        if (d2 < cohD*cohD) { cx += b.x; cy += b.y; cc++; }
      }

      if (sc > 0) { a.vx += (sx/sc) * sepK * dt; a.vy += (sy/sc) * sepK * dt; }
      if (ac > 0) { a.vx += ((ax/ac) - a.vx) * aliK * dt; a.vy += ((ay/ac) - a.vy) * aliK * dt; }
      if (cc > 0) { a.vx += ((cx/cc) - a.x) * cohK * dt; a.vy += ((cy/cc) - a.y) * cohK * dt; }

      // speed limit
      const sp = Math.sqrt(a.vx*a.vx + a.vy*a.vy) + 1e-6;
      const maxSp = params.maxSpeed || 0.3;
      if (sp > maxSp) { a.vx = a.vx / sp * maxSp; a.vy = a.vy / sp * maxSp; }
    }

    for (const a of boids) {
      a.x = (a.x + a.vx * dt + 1) % 1;
      a.y = (a.y + a.vy * dt + 1) % 1;
    }
    return { boids };
  }
};

