// Simple KMeans-ish clustering on pixel samples (no model)
const state = { centers: null };
return {
  state,
  update: async (t, inputs) => {
    const img = inputs && (inputs.image || inputs.main);
    if (!img) return state;
    const x = tf.tidy(() => tf.browser.fromPixels(img).toFloat().div(255).reshape([-1, 3]));
    const k = Math.max(2, Math.floor(params.k || 4));
    // random init
    let centers = tf.gather(x, tf.randomUniform([k], 0, x.shape[0], 'int32'));
    for (let it = 0; it < (params.iters || 4); it++) {
      const d = tf.sum(tf.square(tf.expandDims(x, 1).sub(tf.expandDims(centers, 0))), 2); // NxK
      const a = tf.argMin(d, 1); // N
      const one = tf.oneHot(a, k);
      const sums = tf.matMul(one.transpose(), x);
      const counts = tf.sum(one, 0).reshape([k, 1]).add(1e-6);
